+    fn record_max_active(max_active: &AtomicUsize, current: usize) {
+        let mut observed = max_active.load(Ordering::Relaxed);
+        while current > observed {
+            match max_active.compare_exchange_weak(
+                observed,
+                current,
+                Ordering::Relaxed,
+                Ordering::Relaxed,
+            ) {
+                Ok(_) => break,
+                Err(actual) => observed = actual,
+            }
+        }
+    }
